+{"version":3,"sources":["../../../src/core/ConfigManager.ts"],"sourcesContent":["/**
 * ConfigManager - Handles configuration validation and setup
 * Manages environment variables, file-based config, and validation schemas
 */

import * as fs from 'fs-extra';
import * as path from 'path';
import { ConfigValidationResult, InitConfig, DatabaseConfig, TopologyConfig } from '../types/interfaces.js';

export interface ClaudeFlowConfig {
  // Core settings
  mode?: string;
  topology?: string;
  maxAgents?: number;
  strategy?: string;

  // Database configuration
  database?: DatabaseConfig;

  // Topology configuration
  topologyConfig?: TopologyConfig;

  // MCP integration
  mcpServers?: MCPServerConfig[];

  // GitHub integration
  github?: GitHubConfig;

  // Neural network settings
  neural?: NeuralConfig;

  // Hive mind settings
  hiveMind?: HiveMindConfig;

  // Enterprise features
  enterprise?: EnterpriseConfig;

  // Debugging and logging
  debug?: boolean;
  logLevel?: 'error' | 'warn' | 'info' | 'debug';
  logPath?: string;

  // Performance settings
  performance?: PerformanceConfig;
}

export interface MCPServerConfig {
  name: string;
  command: string;
  args?: string[];
  env?: Record<string, string>;
  enabled: boolean;
}

export interface GitHubConfig {
  token?: string;
  owner?: string;
  repo?: string;
  webhookSecret?: string;
  autoSync?: boolean;
}

export interface NeuralConfig {
  modelPath?: string;
  wasmOptimization?: boolean;
  simdAcceleration?: boolean;
  trainingEnabled?: boolean;
}

